@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This site uses cookies to improve your experience. We collect only the data
    necessary to operate the application and do not share personal information
    with third parties.
</p>

<h2>Cookie Consent</h2>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented =>
        HttpContext?.Request.Cookies.ContainsKey("consent") is true;
}

